mapper.select:
SELECT 
FROM overtime_applications
WHERE employee_id = #{employeeId}
  AND EXTRACT(YEAR FROM overtime_date) = #{year}
  AND EXTRACT(MONTH FROM overtime_date) = #{month}
  AND (is_deleted IS NULL OR is_deleted = 0)
ORDER BY overtime_date

